const { MongoClient } = global.get('mongodb') || require('mongodb');
const uri = process.env.MONGODB_URI;

if (!uri) {
    node.error('MONGODB_URI is missing from environment variables');
    return null;
}

(async () => {
    const client = new MongoClient(uri);
    try {
        await client.connect();
        const db = client.db('Vitals_Monitoring');

        // 1. Save incoming reading from ESP32
        const incoming = msg.payload;
        const newDoc = {
            deviceId: incoming.deviceId || 'ESP32_01',
            bpm: Number(incoming.bpm),
            spo2: Number(incoming.spo2),
            bodyTemp: Number(incoming.bodyTemp),
            timestamp: new Date().toISOString()
        };
        await db.collection('telemetry').insertOne(newDoc);

        // 2. Fetch trailing 6 readings for Groq Context timeline
        const history = await db.collection('telemetry')
            .find({ deviceId: newDoc.deviceId })
            .sort({ timestamp: -1 })
            .limit(6)
            .toArray();

        // 3. Fetch custom upper/lower targets
        const config = await db.collection('device_configs')
            .findOne({ deviceId: newDoc.deviceId }) || {
                minBPM: 60, maxBPM: 100,
                minSpO2: 95, maxSpO2: 100,
                minTemp: 36.0, maxTemp: 37.5
            };

        msg.payload = {
            current: newDoc,
            history: history.reverse(),
            config: config
        };

        node.send(msg);
    } catch (err) {
        node.error(err);
    } finally {
        await client.close();
    }
})();
return null;

const groqKey = process.env.GROQ_API_KEY;
if (!groqKey) {
    node.error('GROQ_API_KEY environment variable missing');
    return null;
}

const historyText = msg.payload.history.map(h => 
    `Time: ${h.timestamp}, Pulse: ${h.bpm}BPM, SpO2: ${h.spo2}%, Temp: ${h.bodyTemp}°C`
).join('\n');

msg.headers = {
    'Authorization': 'Bearer ' + groqKey,
    'Content-Type': 'application/json'
};

msg.payload = {
    model: 'llama3-8b-8192',
    messages: [
        {
            role: 'system',
            content: 'You are an advanced medical telemetry monitor analyst AI. Analyze the timestamp sequence trend. Output a single, short summary sentence predicting if the user\'s vitals are stabilizing, degrading, or displaying abnormal volatility patterns.'
        },
        {
            role: 'user',
            content: `Analyze this trailing stream timeline data:\n${historyText}`
        }
    ]
};

// Keep old data configuration values saved in an alternate object tracker container
msg.vitalsContext = msg.payload.history;
msg.configContext = msg.payload.config;

return msg;

const { MongoClient } = global.get('mongodb') || require('mongodb');
const uri = process.env.MONGODB_URI;

const aiAnalysisText = msg.payload?.choices?.[0]?.message?.content || 'Analysis unavailable';
const history = msg.vitalsContext;
const lastReading = history[history.length - 1];
const cfg = msg.configContext;

// Append the AI prediction right into our latest reading record item context structure
(async () => {
    const client = new MongoClient(uri);
    try {
        await client.connect();
        const db = client.db('Vitals_Monitoring');
        await db.collection('telemetry').updateOne(
            { _id: lastReading._id },
            { $set: { aiAnalysis: aiAnalysisText } }
        );
    } catch(e) { 
        node.error('Failed appending AI data string', e);
    } finally {
        await client.close();
    }
})();

// 2. Evaluate dual system margins limits
let alerts = [];
if (lastReading.bpm < cfg.minBPM) alerts.push(`Low Pulse: ${lastReading.bpm} BPM (Min target: ${cfg.minBPM})`);
if (lastReading.bpm > cfg.maxBPM) alerts.push(`High Pulse: ${lastReading.bpm} BPM (Max target: ${cfg.maxBPM})`);

if (lastReading.spo2 < cfg.minSpO2) alerts.push(`Critical Oxygen drop: ${lastReading.spo2}% (Min safety: ${cfg.minSpO2}%)`);
if (lastReading.spo2 > cfg.maxSpO2) alerts.push(`Oxygen value surge: ${lastReading.spo2}% (Max limit: ${cfg.maxSpO2}%)`);

if (lastReading.bodyTemp < cfg.minTemp) alerts.push(`Low Body Temp: ${lastReading.bodyTemp}°C (Min target: ${cfg.minTemp}°C)`);
if (lastReading.bodyTemp > cfg.maxTemp) alerts.push(`Fever Warning: ${lastReading.bodyTemp}°C (Max safety: ${cfg.maxTemp}°C)`);

if (alerts.length > 0) {
    msg.to = "your-alert-inbox@gmail.com"; 
    msg.topic = "⚠️ EMERGENCY HEALTH ALERT: " + lastReading.deviceId;
    msg.payload = `Emergency health metrics breach detected for device: ${lastReading.deviceId}.\n\nFlags Raised:\n- ${alerts.join('\n- ')}\n\nAI Trend Insight Analysis:\n${aiAnalysisText}\n\nLive Metrics Context Tracker Stream:\nPulse: ${lastReading.bpm} BPM | SpO2: ${lastReading.spo2}% | Temp: ${lastReading.bodyTemp}°C`;
    return msg;
}

return null;
